CREATE TABLE numbers (n INT PRIMARY KEY);

DELIMITER $$
CREATE PROCEDURE fill_numbers(IN up_to INT)
BEGIN
    DECLARE i INT DEFAULT 1;
    WHILE i <= up_to DO
        INSERT INTO numbers VALUES (i);
        SET i = i + 1;
    END WHILE;
END$$
DELIMITER ;

CALL fill_numbers(5);
